"""
mkt-context — Nehemiah chapters 7–8
Run: python3 scripts/zc-context-nehemiah-7-8.py

Ch 7 (73v): Appointment of gatekeepers (vv1-3); city underpopulation (vv4-5);
  the genealogical census register (vv6-73), a nearly identical parallel to Ezra 2
  drawn from the same Persian administrative document.
Ch 8 (18v): The Torah reading ceremony at the Water Gate — Ezra reads from
  dawn to midday; Levites explain the text; the people feast; Feast of Tabernacles
  discovered and celebrated.

Key contextual observations:
- 7:2 — bîrāh (citadel/fortress) is the Persian term for the administrative garrison
- 7:5 — the genealogical register is a Persian administrative census document
- 7:7 — the list of 11 leaders corresponds to the 12 tribes minus Levi — or 12 names
- 7:64 — the Urim and Thummim had ceased functioning by the post-exilic period
- 8:4 — migdal-ʿēṣ (wooden tower/pulpit) is earliest literary evidence for a reading bimah
- 8:8 — the Levites' role anticipates the synagogue targum-and-homily practice
- 8:17 — 'since the days of Joshua' is rhetorical intensification, not strict history
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(book, type_):
    p = ROOT / 'data' / 'commentary' / f'mkt-{type_}' / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(book, type_, data):
    p = ROOT / 'data' / 'commentary' / f'mkt-{type_}' / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

NEH_CONTEXT = {
  "7": {
    "1": "<p>The wall completion ceremony marks the transition from construction to governance. The three roles appointed — <em>šōʿᵃrîm</em> (gatekeepers), <em>mᵉšōrᵃrîm</em> (singers), and <em>lᵉwiyyîm</em> (Levites) — represent the full cultic-administrative apparatus of a functioning city-sanctuary. In the ancient Near East, city gates were not merely military structures; they were the loci of legal proceedings, commercial transactions, and civic authority. Appointment of gatekeepers was therefore both a security and an administrative act.</p>",
    "2": "<p>Hanani was Nehemiah's brother who had first brought news of Jerusalem's condition to Susa (Neh 1:2), making his appointment as commander of Jerusalem a trust-based assignment consistent with ancient patronage networks. Hananiah is identified as the <em>śar habîrāh</em> — commander of the <em>bîrāh</em>, the Persian administrative citadel. <em>Bîrāh</em> is an Akkadian loan word (*bīrtu*, fortress/palace) used in Persian administrative texts for the garrison headquarters; in Jerusalem this was probably the fortified area on the north side of the temple mount that later Persian texts (and Nehemiah 2:8) identify as the fortress. Hananiah's qualification is stated in covenantal terms: 'he was a more faithful and God-fearing man than many' — the criterion is personal character, not military rank.</p>",
    "3": "<p>Nehemiah's security directive — gates not opened until the sun is well up, and guards appointed from among the local inhabitants rather than professional soldiers — reflects the security realities of an underpopulated city. Ancient city gates were typically opened at dawn; Nehemiah's requirement to wait 'until the sun is hot' prevented dawn raids by raiders who might exploit the change of guard. Each household assigned to guard the section opposite their own house (a principle also used in the wall-building of ch3) made each family personally invested in the security of their own neighborhood.</p>",
    "4": "<p>'The city was wide and large, but the people within it were few, and no houses had been rebuilt' — this description is important archaeological and demographic context. Persian-period Jerusalem was a fraction of the size of pre-exilic Jerusalem; the city walls that Nehemiah had just rebuilt enclosed a much larger area than the population could fill. Archaeological surveys confirm that 5th-century BCE Jerusalem was a small community concentrated around the temple mount and the southeastern hill (the original City of David), with most of the walled area empty or sparsely inhabited.</p>",
    "5": "<p>'My God put it in my heart to assemble the nobles, the officials, and the people to be enrolled by genealogy.' The genealogical census served multiple Persian administrative purposes: it established who had the right to land within Yehud's borders (land tenure depended on ancestral claim), who could claim tax-exempt status as priestly families, and who qualified for temple service roles. The phrase <em>sēper hayyaḥaś</em> ('the book of genealogy') refers to the same census document preserved in Ezra 2 — Nehemiah discovers the original administrative register from the first return wave and uses it as the baseline for his repopulation effort.</p>",
    "6": "<p>The heading of the census list: 'these are the people of the province who came up from the captivity of the exile.' <em>Hammᵉḏînāh</em> (the province) is the Persian administrative term for Yehud as a sub-unit of the satrapy Beyond the River (<em>Abar-Nahara</em>). The phrase 'those whom Nebuchadnezzar king of Babylon had carried into exile' frames the whole list as a story of reversal — the same community disrupted by Nebuchadnezzar is now reconstituting itself under Persian authorization. The list is organized with lay families first, then priestly and Levitical, a standard administrative format.</p>",
    "7": "<p>The eleven leaders named at the head of the return: Zerubbabel, Jeshua, Nehemiah (a different Nehemiah from the book's protagonist), Azariah, Raamiah, Nahamani, Mordecai, Bilshan, Mispereth, Bigvai, Nehum/Rehum, Baanah. These eleven or twelve names may correspond to the twelve tribes, with the list functioning as a symbolic census of all Israel rather than a literal headcount of the leaders present. Zerubbabel and Jeshua are the two founding figures of the restoration, named elsewhere as the recipients of Haggai's and Zechariah's oracles.</p>",
    "8": "<p>The family of Parosh: 2,172 men. The individual family counts in the census use the term <em>bᵉnê</em> ('sons of') followed by the family head's name, then a count of adult males — the standard format of Persian administrative registers (<em>daiva*bāra-*</em> in the Persian record tradition). The counts reflect only adult men capable of military service, not total population; total population (including women, children, and non-citizen servants) would have been 3-5 times higher.</p>",
    "9": "<p>The family of Shephatiah: 372. The name means 'YHWH has judged'; it appears multiple times in pre-exilic records. The relatively small size of some families in the list (compared to Parosh's 2,172) reflects the varying survival rates of different clans through the Babylonian exile — some families were deported in larger numbers, some had high mortality, and some had greater success maintaining family cohesion across generations in Babylon.</p>",
    "10": "<p>The family of Arah: 652 (Ezra 2:5 has 775 — one of the notable discrepancies between the two lists). This discrepancy and others like it suggest that Ezra 2 and Nehemiah 7 are independent transmissions of the same source document, with copyists introducing errors (transposition of digits, misreading of letters) through separate scribal traditions. The differences do not indicate fabrication but rather normal variance in manuscript transmission of number-lists.</p>",
    "11": "<p>The family of Pahath-moab, including sub-families of Jeshua and Joab: 2,818 (Ezra 2:6 has 2,812 — six fewer). <em>Paḥaṯ-mōʾāḇ</em> means 'governor of Moab,' suggesting this family's ancestor had governed or served in Moab during the monarchy period. Combined family groups like this (Pahath-moab subsumes Jeshua and Joab's lines) reflect that by the return generation, some originally distinct family lines had merged administratively.</p>",
    "12": "<p>The family of Elam: 1,254. Elam is both a geographic reference (the ancient state east of Babylon) and a personal name common in Israel. This group may represent Israelites who had settled in Elam during the Assyrian exile and reached Babylon for the Persian return, or it may be a family of Israelite origin whose ancestor bore the name Elam.</p>",
    "13": "<p>The family of Zattu: 845. Zattu's descendants appear again in Neh 10:14 among those who sealed the covenant — the same families registered in the census also participate in the formal covenant renewal, showing that the census list and the covenant list are drawn from the same community roster.</p>",
    "14": "<p>The family of Zaccai: 760. The name Zaccai (from <em>zakkāy</em>, 'pure, innocent') appears only here and in Ezra 2:9. The size of this family (760 adult males) makes it a substantial clan within the restored community, yet it appears only in census lists — no individual Zaccaite is mentioned in the narrative sections of Ezra-Nehemiah.</p>",
    "15": "<p>The family of Binnui: 648 (Ezra 2:10 has 'Bani: 642' — a name variant and number discrepancy). The alternation between 'Binnui' (Nehemiah 7) and 'Bani' (Ezra 2) for the same family reflects either a textual corruption of the name or the use of a shortened form in one source. Binnui/Bani's descendants are prominent in the Ezra-Nehemiah narrative as wall-builders and covenant-signers.</p>",
    "16": "<p>The family of Bebai: 628 (Ezra 2:11 has 623). Bebai's descendants appear in Ezra 8:11 as one of the groups who returned with Ezra in 458 BCE — the same family that registered in the first return (538 BCE) is still returning members from Babylon in the second return, suggesting that the family had members in both waves of migration.</p>",
    "17": "<p>The family of Azgad: 2,322 (Ezra 2:12 has 1,222 — a major discrepancy). This is one of the largest numerical differences between the two lists. The difference may reflect a scribal error in copying large numbers, or the two lists may record the family at different points in time with genuine growth between registrations. Azgad's descendants also return with Ezra (Ezra 8:12), confirming multi-generational family connections to the land.</p>",
    "18": "<p>The family of Adonikam: 667 (Ezra 2:13 has 666). The name <em>ʾAḏōnîqam</em> ('my Lord has risen') is attested in pre-exilic records. The difference of one in the total (667 vs. 666) is the kind of minor variant that can arise from whether the final tally included a newborn or late-comer — suggesting the two records were compiled at slightly different points.</p>",
    "19": "<p>The family of Bigvai: 2,067 (Ezra 2:14 has 2,056). Bigvai is a Persian or Babylonian name borne by a Jewish family that had either intermarried or adopted the naming conventions of the exile culture — a common phenomenon in diaspora communities. Members of Bigvai's family are listed in Ezra 8:14 as returning with Ezra's second wave.</p>",
    "20": "<p>The family of Adin: 655 (Ezra 2:15 has 454 — a significant discrepancy). Adin's descendants appear in the covenant-signing list (Neh 10:16) and in Ezra 8:6 as participants in the second return. The name <em>ʿāḏîn</em> means 'delicate, voluptuous' — an unusual name preserved consistently through multiple lists across the restoration period.</p>",
    "21": "<p>The family of Ater through Hezekiah: 98. The specification 'of Ater, of Hezekiah' indicates the family traced its ancestry to both Ater and the royal line of Hezekiah, a compound genealogical claim that was probably important for property or status rights in the restored community. Priestly and royal genealogical claims were carefully maintained throughout the exile.</p>",
    "22": "<p>The family of Hashum: 328 (Ezra 2:19 has 223 — a notable discrepancy). Hashum's descendants are among those who sealed the covenant (Neh 10:18) and some had married foreign women and were required to divorce them under Ezra's reform (Ezra 10:33). The combination of covenant loyalty and mixed marriage within the same family shows the complexity of community boundary-maintenance in the restoration period.</p>",
    "23": "<p>The family of Bezai: 324 (Ezra 2:17 has 323). The name Bezai appears in the covenant-signing list (Neh 10:18). These small numerical variants (324 vs. 323) are typical of scribal transcription of number-lists and indicate independent copying of the same source document rather than deliberate alteration.</p>",
    "24": "<p>The family of Hariph: 112. Hariph is specifically listed in the covenant-signing ceremony (Neh 10:19), one of only a few family names that appears both in the census list and the covenant list with the same spelling. In Ezra 2:18, the parallel entry is 'Jorah: 112' — another name-variant between the two lists that may reflect a family known by two different names or a scribal confusion between similar-looking letters.</p>",
    "25": "<p>The men of Gibeon: 95. This entry shifts from personal-name families to geographic families — communities that returned as town-based groups rather than genealogically-defined families. Gibeon was one of the Hivite cities that had tricked Joshua into a treaty (Josh 9), and its residents had been assigned as temple servants. The Gibeonites returning as a geographic unit suggests they maintained a distinct community identity through the exile.</p>",
    "26": "<p>The men of Bethlehem and Netophah: 188. Bethlehem was the hometown of David and the ancestral home of the Boaz-Ruth-Obed line; its relatively small contingent of returnees (combined with Netophah) reflects the destruction of the Judean countryside, where towns like Bethlehem may have survived with reduced populations rather than being fully depopulated.</p>",
    "27": "<p>The men of Anathoth: 128. Anathoth was the Levitical city assigned to Abiathar (1 Kgs 2:26), the hometown of Jeremiah (Jer 1:1). The returnees from Anathoth are listed among the lay families rather than the Levitical section, suggesting that by the return period, Anathoth had become primarily a lay town, with any Levitical families counted separately in the Levitical section.</p>",
    "28": "<p>The men of Beth-azmaveth: 42. The place Beth-azmaveth (or Azmaveth, Ezra 2:24) was a Benjaminite town northeast of Jerusalem. The small number (42) reflects the marginal position of smaller towns in the return — many had no surviving community to return as an organized group, so only stray families from major towns appear in the register.</p>",
    "29": "<p>The men of Kiriath-jearim, Chephirah, and Beeroth: 743. These three towns are grouped together because they were the Gibeonite cities whose inhabitants had treaty rights with Israel (Josh 9:17); their combination into a single entry reflects their status as a recognized administrative cluster from pre-exilic times. Kiriath-jearim was where the ark rested for 20 years after its return from the Philistines (1 Sam 7:1-2).</p>",
    "30": "<p>The men of Ramah and Geba: 621. Ramah was Samuel's hometown and the site of the first Israelite kingship establishment; Geba was a Levitical city in Benjamin marking the southern boundary of Benjamin proper (Zech 14:10). The pairing of these administratively distinct towns into a single entry probably reflects their geographic proximity and shared communal identity after the exile.</p>",
    "31": "<p>The men of Michmas: 122. Michmas (modern Mukhmas) was the site of Jonathan's heroic assault on the Philistine garrison (1 Sam 13-14) and sat on the main road north of Jerusalem through the central highlands. Its 122 returnees suggest a viable but small community that had survived the Babylonian period in place or in exile.</p>",
    "32": "<p>The men of Bethel and Ai: 123. Bethel was the site of Jacob's vision and later Jeroboam's calf-cult; Ai was the town near which Achan's sin caused Israel's initial defeat (Josh 7). Both towns carry heavy theological weight in the tradition; the small number of returnees (123 for two historically significant towns combined) suggests both had been largely destroyed and only minimal populations survived.</p>",
    "33": "<p>The men of the other Nebo: 52. 'The other Nebo' distinguishes this Benjaminite town from the Transjordanian Mount Nebo where Moses died (Deut 34:1). The qualifier 'other' suggests the scribe who compiled the list was aware of the geographic ambiguity and specified which Nebo was meant — an example of the editorial care taken with this administrative document.</p>",
    "34": "<p>The family of the other Elam: 1,254. 'The other Elam' distinguishes this family from the first Elam of v12 — two families bearing the same ancestral name are counted separately. Both have the same count (1,254), which may be coincidence or may indicate that by the second registration both branches of the Elam family had grown to the same size.</p>",
    "35": "<p>The family of Harim: 320. Harim was one of the larger priestly families in the first return (Ezra 2:39: 1,017 priests of Harim), but here in the lay section it refers to a different family bearing the same name. The same name being carried by both priestly and lay families was common in Israel, where names with theophoric or honorific meanings were distributed across social classes.</p>",
    "36": "<p>The men of Jericho: 345. Jericho, the first city conquered by Joshua, sits in the Jordan valley and would have been one of the first communities encountered by returnees entering the land from the Transjordanian crossing. Its significant count (345) reflects either good survival or active rebuilding; by Elijah's time it had been rebuilt (1 Kgs 16:34) and it maintained a community through the monarchic and exilic periods.</p>",
    "37": "<p>The men of Lod, Hadid, and Ono: 721. This cluster of towns in the coastal plain (the Shephelah border region) represents Israelites who had remained in or returned to territory that was on the edge of the Persian Yehud province. The large combined count (721) suggests this western region survived the Babylonian period relatively well — it was less directly targeted by the Babylonian army's Jerusalem-focused campaign.</p>",
    "38": "<p>The family of Senaah: 3,930. This is the largest single entry in the census, with the largest individual number. Senaah appears nowhere else in the narrative, making it either a very large family of obscure origin or possibly a term for day-laborers or a special category of persons whose family designation was their occupation or status rather than genealogy. Some scholars suggest <em>sᵉnāʾāh</em> may mean 'those who are hated/despised' — a social designation for the lowest community stratum.</p>",
    "39": "<p>The priestly families section begins: the family of Jedaiah through Jeshua's house, 973. Jedaiah's priestly family was one of the most prominent in the post-exilic community; the specification 'of the house of Jeshua' may indicate that this branch of Jedaiah's family was associated with the high priest Jeshua's household — either as relatives or as client priests in his household's administrative network.</p>",
    "40": "<p>The family of Immer: 1,052. Immer was one of the major priestly divisions; Pashhur son of Immer was the priest who had Jeremiah put in stocks (Jer 20:1), making this family's ancestor one of the pre-exilic cultic authorities who had opposed the prophetic tradition. The descendants of that same family are now enumerated among the restored community's priestly contingent.</p>",
    "41": "<p>The family of Pashhur: 1,247. Pashhur was another priestly family name; its large count (1,247) makes it one of the largest priestly families in the return. There was more than one Pashhur in the pre-exilic record (Jer 20:1; Jer 38:1), and the post-exilic family's name may derive from one or both of these prominent pre-exilic priestly figures.</p>",
    "42": "<p>The family of Harim the priest: 1,017. This is the largest single priestly family in the census. Harim appears in both Ezra's list and here as a major priestly contingent; the size of this family (over 1,000) suggests it was one of the dominant priestly clans of the pre-exilic period. The priestly families collectively (973+1,052+1,247+1,017 = 4,289) constitute a significant proportion of the total returnees.</p>",
    "43": "<p>The Levites: families of Jeshua and Kadmiel through the family of Hodaviah: 74. The disproportionately small Levitical contingent (74 vs. over 4,000 priests) was a recurring problem of the restoration period. Ezra 8:15-20 records that when Ezra prepared for his own journey to Jerusalem, he discovered 'no Levites' among his company and had to specifically recruit them from Casiphia. The Levites' reluctance to return probably reflects better economic conditions in Babylon and the less prestigious role Levites held compared to priests.</p>",
    "44": "<p>The singers: family of Asaph, 148. The Asaphite singers represent the musical institution that David had established; they are listed separately from the Levites even though singers were technically Levitical because their specialized function gave them a distinct institutional identity. 148 singers (vs. 74 Levites) suggests the musical tradition was more successfully maintained and transmitted through the exile than the general Levitical service.</p>",
    "45": "<p>The gatekeepers: families of Shallum, Ater, Talmon, Akkub, Hatita, and Shobai — 138 total. The gatekeepers were also Levitical in origin (1 Chr 9:22-27) but like the singers had developed a specialized institutional identity. Their function was both cultic (guarding the temple gates) and civic-military (controlling access to the city's fortified area). 138 gatekeepers for a city of several thousand would have provided minimal staffing for the multiple city gates.</p>",
    "46": "<p>The Nethinim section begins. The Nethinim (<em>nᵉṯînîm</em>, 'those given') were temple servants assigned to assist the Levites in their work. Their origin is described in Ezra 8:20 as 'those whom David and the officials had given for the service of the Levites.' Several theories exist about their origin: descendants of the Gibeonites given to temple service (Josh 9:27); war captives from various campaigns; or a class of non-Israelite workers incorporated into the temple's support staff.</p>",
    "47": "<p>Nethinim families: Ziha, Hasupha, Tabbaoth. The names in the Nethinim lists often have non-Hebrew linguistic backgrounds — Akkadian, Aramaic, and other Semitic forms appear alongside Hebrew names — consistent with the theory that many Nethinim were of foreign origin incorporated into the temple service workforce over centuries of Israelite history.</p>",
    "48": "<p>Nethinim: Keros, Sia, Padon. The presence of non-Hebrew names (Keros from a root related to 'weaving'; Padon possibly related to a Babylonian place name) alongside Hebrew names in the Nethinim list reflects the multi-ethnic composition of the temple's support staff. These families maintained their distinct identity through the exile and returned as a recognized institutional group.</p>",
    "49": "<p>Nethinim: Lebana, Hagaba, Shalmai. These three names appear consistently across Ezra 2 and Nehemiah 7 (with minor spelling variants), suggesting they were well-established Nethinim families with strong institutional memory. The Nethinim lists in these chapters preserve the names of groups whose origin stories have otherwise been lost.</p>",
    "50": "<p>Nethinim: Hanan, Giddel, Gahar. Hanan appears as a common name in the restoration community (several prominent figures bear it); the appearance of Hanan among the Nethinim shows that the name crossed social class boundaries. The Nethinim were socially distinct from the lay Israelites and the priestly-Levitical classes but were fully part of the covenant community.</p>",
    "51": "<p>Nethinim: Reaiah, Rezin, Nekoda. Rezin was the name of the last Aramean king of Damascus (Isa 7:1), suggesting this Nethinim family may have had Aramean origin — war captives from Israel's campaigns against Damascus who were incorporated into temple service. The presence of such names demonstrates that the temple's workforce was genuinely multi-ethnic.</p>",
    "52": "<p>Nethinim: Gazzam, Uzza, Paseah. Gazzam may relate to a Hebrew word for 'locust' and Paseah to 'limping' — names that may have been descriptive nicknames adopted as family identifiers. The adoption of such names suggests these families had been in the region long enough to acquire Hebrew/Aramaic naming conventions while maintaining their distinct Nethinim identity.</p>",
    "53": "<p>Nethinim: Besai, Meunim, Nephushesim. Meunim refers to the people of Ma'on, a semi-nomadic group east of Jordan (2 Chr 26:7; Neh 3:26); their descendants apparently entered temple service, possibly after military defeat by Uzziah. Nephushesim derives from Naphish, a son of Ishmael (Gen 25:15), suggesting Ishmaelite origin for this Nethinim family.</p>",
    "54": "<p>Nethinim: Bakbuk, Hakupha, Harhur. The linguistic backgrounds of these names are unclear, but Hakupha has been connected to Egyptian and Aramaic forms. The diversity of name origins in the Nethinim list is one of the strongest pieces of evidence for the multi-ethnic composition of Jerusalem's temple workforce over the centuries of the monarchy.</p>",
    "55": "<p>Nethinim: Bazluth, Mehida, Harsha. Harsha may derive from a root meaning 'deaf/silent' — either a descriptive name or a foreign name Hebraized through folk etymology. These families maintained enough organizational coherence through the Babylonian exile to return as identifiable institutional groups to their temple-service function.</p>",
    "56": "<p>Nethinim: Barkos, Sisera, Tamah. Sisera is the name of the Canaanite general defeated by Deborah and Barak (Judg 4-5), and the appearance of his name among the Nethinim may indicate that survivors of his defeated army were incorporated into Israelite temple service — a possible historical echo of the conquest period's treatment of defeated enemies.</p>",
    "57": "<p>Nethinim: Neziah, Hatipha. With these two entries the Nethinim list concludes and the 'servants of Solomon' category begins. The 'servants of Solomon' (<em>ʿaḇdê šᵉlōmōh</em>) were a distinct group of temple workers whose origin was traced to Solomon's use of non-Israelite labor in the temple construction (1 Kgs 9:20-21). They had a separate identity from the Nethinim though both groups served the temple.</p>",
    "58": "<p>Servants of Solomon: Sotai, Sophereth, Perida. Sophereth means 'scribe/secretary' — a name indicating this family's ancestors served in an administrative capacity in Solomon's court or temple. The preservation of occupational names as family identifiers across centuries of exile shows the persistence of institutional memory even in diaspora conditions.</p>",
    "59": "<p>Servants of Solomon: Jaala, Darkon, Giddel. Darkon may be a Persian or Babylonian name incorporated into this list, suggesting that some 'servants of Solomon' families had intermarried with the general Babylonian population and adopted local names while maintaining their distinct covenant-community identity. Their return to Jerusalem restored the full institutional apparatus of the temple workforce.</p>",
    "60": "<p>The combined total of Nethinim and servants of Solomon: 392. This total confirms the separate counts across vv46-59 and provides the administrative closing for this section. The relatively small number (392 for two distinct institutional groups) reflects the expected attrition across generations of exile, but also the survival of these specialized groups as identifiable communities.</p>",
    "61": "<p>Those who could not prove their ancestry: from Tel-melah, Tel-harsha, Cherub, Addon, and Immer — these are places in Babylon where Jewish exiles had settled. <em>Tel-melah</em> ('mound of salt') and <em>Tel-ḥarša</em> ('mound of craftsmen') are tell-mounds in Babylonia with Semitic place names. The geographic-origin-based identification (rather than ancestral-name-based) marks these as families who had lost their genealogical records in the exile — a significant social disability in a community where genealogy determined land rights, priestly eligibility, and covenant status.</p>",
    "62": "<p>The family of Delaiah, Tobiah, and Nekoda: 642 persons who could not prove their Israelite descent. Tobiah was the name of Nehemiah's Ammonite opponent (Neh 2:10), but this is a different family group; multiple families bore the same names. Being unable to prove genealogical continuity meant these 642 persons lived in an ambiguous legal status — part of the community but without the land-inheritance and social rights that genealogical verification conferred.</p>",
    "63": "<p>Priestly families without documented genealogy: sons of Hobaiah, Hakkoz, and Barzillai. Barzillai the Gileadite was David's loyal supporter during Absalom's rebellion (2 Sam 17:27-29); a priest who married into his family and took the family name lost his priestly genealogical identity in the process. This illustrates the tension between marriage alliance (important for social stability) and genealogical purity (essential for priestly legitimacy) — taking a wife's family name was unusual and had serious legal consequences.</p>",
    "64": "<p>'They searched for their register among those enrolled by genealogy, but it was not found' — the loss of genealogical records was not merely a bureaucratic problem but a crisis of identity and legal standing. <em>Hayyaḥaś</em> (the genealogical register) was the authoritative document; if a family's name was not in the register, their claim to priestly status could not be upheld. The three excluded priestly families were not accused of fraud but of documentary loss — they were excluded 'as unclean from the priesthood' (<em>wayyᵉgōʾᵃlû min-hakkᵉhunnāh</em>) pending further verification.</p>",
    "65": "<p>The governor's ruling: they could not eat of the most holy things 'until there should be a priest to consult Urim and Thummim.' The Urim and Thummim were oracular lots kept in the high priest's breastplate (Exod 28:30) used for binary decisions in matters of national or cultic importance (1 Sam 14:41-42; 28:6). Significantly, the post-exilic sources consistently refrain from claiming the Urim and Thummim were actually in use — their mention here as a future possibility ('until a priest arises with Urim and Thummim') acknowledges the consensus in later Judaism that this oracle had ceased functioning after the destruction of the first temple. The Talmud (Yoma 21b) lists the Urim and Thummim among the five things the second temple lacked that the first had.</p>",
    "66": "<p>The total count: the whole congregation together was 42,360 — this total appears in both Ezra 2:64 and Nehemiah 7:66 with the same figure, but the sub-totals in both lists add up to only approximately 29,000-31,000, not 42,360. The discrepancy is unexplained but has been noted by scholars since antiquity; one theory is that the 42,360 includes women and children while the sub-totals count only adult men, another that the list as transmitted is incomplete. The figure 42,360 may be symbolic — forty-two is associated with trial periods in biblical numerology.</p>",
    "67": "<p>In addition to the 42,360: 7,337 servants and 245 male and female singers (Ezra 2:65 has 200 singers — another discrepancy between the lists). The singers mentioned here are secular musicians (distinct from the Levitical temple singers), accompanying the wealthy families of the return. The mention of singing men and women among the servants' entourage reflects the normal practice of wealthy households maintaining professional entertainers.</p>",
    "68": "<p>Their horses: 736; their mules: 245. The mention of horses and mules indicates the economic status of the returning community — these were expensive animals associated with administrative and military use. Mules in particular were used for mountain transport and were valuable enough to be listed among the most prestigious elements of a noble's household (2 Sam 13:29; 1 Kgs 1:33).</p>",
    "69": "<p>Their camels: 435; their donkeys: 6,720. The ratio of donkeys to other animals reflects the practical reality of Near Eastern travel — donkeys were the standard beast of burden for the majority of goods. 6,720 donkeys for approximately 50,000 people would represent roughly one pack animal per 7 persons, a reasonable ratio for a long-distance migration carrying household goods, tools, and provisions for resettlement.</p>",
    "70": "<p>The freewill offerings to the treasury: the governor gave 1,000 gold darics, 50 basins, 530 priests' garments. Gold darics (<em>darkᵉmônîm</em>) were Persian gold coins issued from the reign of Darius I, stamped with an image of the king running with a bow; they were the standard international currency of the Achaemenid period. The offering of priestly garments alongside gold reflects the community's need to outfit the temple service from scratch — the original temple vestments had been lost in the Babylonian conquest.</p>",
    "71": "<p>Some of the heads of fathers' houses gave to the treasury: 20,000 gold darics and 2,200 minas of silver (Ezra 2:69 has 20 minas of gold and 20,200 darics — a complex set of variants). These leadership donations represent the voluntary contributions of the wealthy lay families to the temple restoration fund, following the ancient Israelite tradition of voluntary offerings for the sanctuary (Exod 35:4-29; 1 Chr 29:6-9). The amounts given suggest that some returned families had accumulated significant wealth during the Babylonian exile.</p>",
    "72": "<p>What the rest of the people gave: 20,000 gold darics, 2,000 minas of silver, and 67 priestly garments. The distinction between 'heads of fathers' houses' (v71) and 'the rest of the people' (v72) reflects the stratified giving structure of the ancient Near Eastern temple economy — leadership gave large lump sums while the general population contributed in smaller amounts that collectively matched or exceeded the elite donations.</p>",
    "73": "<p>So the priests, the Levites, the gatekeepers, the singers, some of the people, the Nethinim, and all Israel settled in their towns. The final verse of the census section: the restored community is enumerated, distributed, and resident. The Seventh month (<em>ḥōḏeš haššᵉḇîʿî</em>) is the month of Tishri (September-October), which contains three major feasts: Rosh Hashanah (1 Tishri), Yom Kippur (10 Tishri), and Sukkot (15-21 Tishri). The transition to ch8 occurs in this same seventh month, connecting the census distribution to the immediate ceremonial life of the community.</p>"
  },
  "8": {
    "1": "<p>The assembly at the Water Gate (<em>šaʿar hammāyim</em>) on the first of the seventh month (Tishri 1) corresponds to what later became Rosh Hashanah, the Jewish New Year. The Water Gate was on the eastern side of the city, giving access to the Gihon spring in the Kidron valley; the broad open plaza before it served as Jerusalem's primary public gathering space. The people assembled 'as one man' (<em>kᵉʾîš ʾeḥāḏ</em>) — the identical phrase used of Israel's assembly at Mizpah in Judg 20:1, evoking the unity of the covenant people gathered for a decisive moment. Their request is specifically for Ezra to bring 'the book of the Law of Moses' — <em>sēper tôraṯ-mōšeh</em>, the authoritative written Torah document.</p>",
    "2": "<p>Ezra the priest brought the Torah 'before the assembly' (<em>haqāhāl</em>) 'of men and women and all who could understand' — the inclusivity of the gathering is remarkable by ancient standards. The assembly included women (whose public Torah exposure was not standard in all ancient contexts) and children 'who could understand' — an age-based cognitive criterion rather than a fixed age. The date (first day of the seventh month) was already a sacred day in the Mosaic calendar (Lev 23:23-25), making this assembly both a civil assembly and a liturgical ceremony.</p>",
    "3": "<p>'He read from it facing the square before the Water Gate from early morning until midday' — approximately five to six hours of continuous reading. The crowd's sustained attention ('the ears of all the people were attentive to the Book of the Law') is presented as a sign of spiritual receptivity after the long exile. Ancient public readings were common in the Near East — Persian administrative edicts were read publicly, and the Torah's public reading tradition traced to Moses' command (Deut 31:11-13); but a six-hour public reading was extraordinary and signals the occasion's solemnity.</p>",
    "4": "<p>Ezra stood 'on a wooden platform (<em>migdal-ʿēṣ</em>)' — a 'wooden tower' built for the purpose. This is the earliest literary evidence for a purpose-built reading platform in Jewish practice; the later synagogue <em>bīmāh</em> (reading platform) traces its institutional ancestry to this structure. Thirteen men stood on his right and left — the symbolic number suggests deliberate organizational planning. Their presence gave visual weight to the reading and may indicate that they read portions of the text in turn.</p>",
    "5": "<p>'When Ezra opened the book, all the people stood up' — this standing for the Torah opening became the normative practice in synagogue liturgy (still observed today). The spontaneous standing of the entire crowd (before any instruction to stand) represents the community's instinctive reverence for the written Torah as YHWH's word. The Torah was not merely an administrative document but the covenantal instrument through which YHWH himself addressed the community.</p>",
    "6": "<p>Ezra's blessing: 'Blessed be YHWH, the great God!' The people's response: 'Amen, Amen!' with uplifted hands, then prostration 'with their faces to the ground.' This liturgical sequence — blessing, double Amen, prostration — is the earliest clear attestation of the congregational liturgical response pattern that would structure synagogue worship. The double Amen (<em>ʾāmēn ʾāmēn</em>) indicates emphatic agreement rather than mere acknowledgment; the uplifted hands are the standard posture of prayer (1 Kgs 8:22; Ps 28:2) and the prostration signals complete submission to the God whose word they are about to receive.</p>",
    "7": "<p>The Levites named here — Jeshua, Bani, Sherebiah, Jamin, Akkub, Shabbethai, Hodiah, Maaseiah, Kelita, Azariah, Jozabad, Hanan, Pelaiah — are thirteen in number, probably corresponding to the thirteen men on Ezra's right and left in v4. These Levites 'helped the people understand the Law' (<em>mᵉḇînîm ʾeṯ-hāʿām battôrāh</em>) — their function was interpretive, not merely vocal. The Levites circulated among the assembled people rather than standing at the platform, providing face-to-face explanation of the text as it was read.</p>",
    "8": "<p>'They read from the book, from the Law of God, clearly (<em>mᵉpōrāš</em>), and they gave the sense (<em>wᵉśôm śeḵel</em>), so that the people understood the reading (<em>wattāḇînû bammiqrāʾ</em>).' The term <em>mᵉpōrāš</em> (clearly, distinctly, or 'made explicit') has been interpreted by rabbinic tradition as referring to Aramaic translation — the targum — since much of the crowd was more fluent in Aramaic after generations in Babylon. 'Giving the sense' (<em>śîm śeḵel</em>) represents the homiletical explanation of the meaning, which became the central function of the synagogue sermon. This verse is frequently cited as the scriptural basis for the synagogue practice of Torah reading followed by interpretation.</p>",
    "9": "<p>The people's response to the Torah reading was weeping — an instinctive reaction to the realization of how far from covenant observance they had fallen, or to the beauty and weight of the word after so long without it. Nehemiah (the governor, <em>hattiršāṯāʾ</em> — the Persian title for the provincial governor), Ezra the priest-scribe, and the Levites together tell the people: 'Do not mourn or weep.' The day is holy. The leadership redirects grief toward celebration — the Torah's return is a gift, not a judgment, and the proper initial response is joy, not penitence (penitence would come later, in ch9).</p>",
    "10": "<p>'Go eat the fat and drink sweet wine and send portions to anyone who has nothing ready, for this day is holy to our Lord. And do not be grieved, for the joy of YHWH is your strength.' The command to feast and to share ('send portions to anyone who has nothing prepared') reflects the covenant community's social ethics: festivals are occasions for redistributing abundance toward those without resources. The phrase 'the joy of YHWH is your strength' (<em>ḥeḏwaṯ YHWH hîʾ māʿuzzᵉḵem</em>) — 'YHWH's joy is your fortress/protection' — declares that the community's resilience comes not from military or economic resources but from the delight they take in YHWH's presence and word.</p>",
    "11": "<p>'Be quiet, for this day is holy' — the Levites had to calm the weeping crowd. The holiness of the day created a tension: grief at the Torah's content called for weeping; the holiness of the day's sacred time required feasting rather than mourning. The Levites' role as pastoral guides who helped the people navigate this tension is an early example of the Levitical teaching function that would characterize the synagogue leader's role in later Judaism.</p>",
    "12": "<p>'And all the people went their way to eat and drink and to send portions and to make great rejoicing, because they had understood the words that were declared to them.' The joy flows directly from understanding — <em>kî hēḇînû baddᵉḇārîm ʾᵃšer hôḏîʿû lāhem</em>: 'because they understood the words they had been taught.' This causal connection between comprehension and joy is central to the theology of Ezra-Nehemiah: the restoration depends not merely on physical rebuilding but on the community's renewed understanding of the covenant word.</p>",
    "13": "<p>The second day: 'the heads of fathers' houses of all the people, with the priests and the Levites, came together to Ezra the scribe in order to study the words of the Law.' The day after the great public reading, the leadership gathered for a more intensive study session. This gathering of community leaders for Torah study alongside Ezra represents an early model of the leadership-formation function that scribal-priestly scholarship would fulfill — intensive study of the text by those responsible for implementing it in community governance.</p>",
    "14": "<p>'And they found it written in the Law that YHWH had commanded by Moses that the people of Israel should dwell in booths during the feast of the seventh month.' The discovery that Sukkot (Feast of Tabernacles, Lev 23:33-43; Deut 16:13-15) required building and dwelling in <em>sukkōṯ</em> (booths) implies either that the law had been unknown or unobserved for an extended period. The seventh month feast of booths was the agricultural harvest festival that commemorated the wilderness wandering; its revival in the restoration period gave it additional resonance — the community that had just returned from exile now re-enacted the wilderness sojourn of their ancestors.</p>",
    "15": "<p>'Go out to the hills and bring branches of olive, wild olive, myrtle, palm, and other leafy trees to make booths.' The specific plants listed in the booths construction correspond roughly to Leviticus 23:40 ('boughs of goodly trees, branches of palm trees, boughs of thick trees, and willows of the brook'), though the species are not identical. The procurement from the surrounding hills reflects the abundance of vegetation in the hill country around Jerusalem — olive, myrtle, and palm were common enough to be gathered without significant difficulty, making the booths construction feasible for the entire community.</p>",
    "16": "<p>The booths were built 'each on his roof, and in their courts and in the courts of the house of God, and in the square at the Water Gate and in the square at the Gate of Ephraim.' The construction of booths across multiple locations — private rooftops, public courtyards, temple courts, and city squares — created a city-wide transformation. The Water Gate and the Gate of Ephraim were the two major public squares of Jerusalem; their use for booth-construction extended the feast into the civic spaces of the city, making Sukkot a community-wide rather than merely private or cultic event.</p>",
    "17": "<p>'And all the assembly of those who had returned from the captivity made booths and lived in the booths, for from the days of Joshua son of Nun to that day the people of Israel had not done so.' The claim that Sukkot had not been observed since Joshua is a rhetorical intensification rather than strict history — Solomon celebrated Sukkot (1 Kgs 8:65), and Ezra 3:4 records that the returned community observed it in 538 BCE. The statement highlights the exceptional quality of this celebration: the combination of circumstances (newly built wall, Torah rediscovered, community gathered) made this Sukkot uniquely meaningful, not that the feast had literally never been observed. The reference to 'from the days of Joshua' may also echo the dedication ceremonies at Shechem where Joshua renewed the covenant (Josh 24), framing this Sukkot as a covenant-renewal moment of similar magnitude.</p>",
    "18": "<p>'And day by day, from the first day to the last day, he read from the Book of the Law of God.' The seven-day Sukkot feast (15-21 Tishri) was framed throughout by daily Torah readings, with a solemn assembly (<em>ʿᵃṣeret</em>) on the eighth day (22 Tishri, corresponding to the later Shemini Atzeret). The phrase 'according to the rule' (<em>kammišpāṭ</em>) anchors the celebration to the prescriptions of Leviticus 23 and Deuteronomy 16 — the community is not improvising but following the Torah's prescription for the feast's structure.</p>"
  }
}

def main():
    existing = load_comm('nehemiah', 'context')
    merge_comm(existing, NEH_CONTEXT)
    save_comm('nehemiah', 'context', existing)
    added_ch7 = len(NEH_CONTEXT.get('7', {}))
    added_ch8 = len(NEH_CONTEXT.get('8', {}))
    print(f'nehemiah mkt-context ch 7-8: wrote {added_ch7} ch7 verses + {added_ch8} ch8 verses = {added_ch7+added_ch8} total')
    import json as _json, pathlib as _pathlib
    il = _json.loads(_pathlib.Path('data/interlinear/nehemiah.json').read_text())
    out = _json.loads(_pathlib.Path('data/commentary/mkt-context/nehemiah.json').read_text())
    for ch in ['7', '8']:
        il_vv = set(il.get(ch, {}).keys())
        out_vv = set(out.get(ch, {}).keys())
        missing = il_vv - out_vv
        if missing:
            print(f'  ch{ch} STILL MISSING: {sorted(missing, key=int)}')
        else:
            print(f'  ch{ch}: complete ({len(out_vv)} verses)')

if __name__ == '__main__':
    main()
